+    #[test]
+    fn to_transcription_segments_large_timestamps_convert_to_seconds_correctly() {
+        let pilot_segs = vec![TranscriptSegment {
+            start_ms: 3_600_000, // 1 hour
+            end_ms: 7_200_000,   // 2 hours
