+                recommended_order: vec!["whisper_cpp".to_owned()],
+                fallback_active: false,
+                fallback_reason: None,
+                posterior_snapshot: vec![0.5, 0.3, 0.2],
+                calibration_score: 0.8,
+                brier_score: Some(0.1),
