+    /// Build a custom WAV file with configurable fmt fields.
+    fn custom_wav(
+        audio_format: u16,
+        channels: u16,
+        sample_rate: u32,
+        bits_per_sample: u16,
+        data_bytes: &[u8],
+    ) -> Vec<u8> {
